package com.agmsolutions.fabrick_test.service;import com.agmsolutions.fabrick_test.Model.dto.BalanceDto;import com.agmsolutions.fabrick_test.Model.dto.TransactionDto;import com.agmsolutions.fabrick_test.configurations.FabrickApiRest;import com.agmsolutions.fabrick_test.configurations.Response;import com.agmsolutions.fabrick_test.configurations.ResponseList;import lombok.AllArgsConstructor;import org.springframework.core.ParameterizedTypeReference;import org.springframework.stereotype.Service;import java.time.LocalDate;import java.util.List;@Service@AllArgsConstructorpublic class AccountService {    private final FabrickApiRest fabrickApiRest;    public BalanceDto getBalance(Long accountId){        Response<BalanceDto> res= fabrickApiRest.getRestClient()                .get()                .uri("/api/gbs/banking/v4.0/accounts/{accountId}/balance", accountId)                .retrieve()                .body(new ParameterizedTypeReference<>() {});        if (res == null)            throw new RuntimeException("Conto non trovato");        return res.getPayload();    }    public List<TransactionDto> getTransactions(Long accountId, LocalDate fromDate, LocalDate toDate){        Response<ResponseList<TransactionDto>> res = fabrickApiRest.getRestClient()                .get()                .uri("/api/gbs/banking/v4.0/accounts/{accountId}/transactions?fromAccountingDate={from}&toAccountingDate={to}", accountId, fromDate, toDate)                .retrieve()                .body(new ParameterizedTypeReference<>() {});        if (res == null)            throw new RuntimeException("Conto non trovato");        return res.getPayload().getList();    }}